var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……도망쳤나.","JPN":"……逃げたか。","ENG":"…Escaped.","TWN":"……跑掉了嗎？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"시설의 상태는 아무일도 없었던 것 같군.","JPN":"施設の状態を見ると、何もなかったかのようだ。","ENG":"The building’s condition... No evidence of conflict.","TWN":"從現場的狀態看來，好像什麼事都沒發生過一樣。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"도망친 것이 아니라, 도망치게 해 준 것이라면…….","JPN":"逃げたのではなく、わざと逃がしたのなら……","ENG":"If she did not escape, but rather they let her escape...","TWN":"難道她不是自己跑掉，而是故意放她走的……"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"침입자에게 경고한다. 상부에서 보낸 카운터가 가는 중이다.","JPN":"侵入者に警告する。上層部から送られたカウンターがそっちへ向かっている。","ENG":"Warning to the intruder. Counters from the head office are on their way.","TWN":"警告入侵者，制裁者正在前往當中。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"수도를 헤집어 놓는 걸로도 모자라 보안국에 무력으로 침입하다니, 각오는 됐겠지.","JPN":"首都を修羅場にするだけでは飽き足らず、保安局に武力で侵入してくるとは、覚悟はできているのだろうな。","ENG":"It was not enough for you to tear up the capital, but now you are even forcefully trespassing the Department of National Security’s main office.","TWN":"把首都搞得一團糟還不夠，現在竟然還以武力闖進安全局，束手就擒吧！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"네놈은 우리의 조국을 모욕했다. 국민들이 지켜보는 가운데 심판해 주마.","JPN":"お前は祖国を侮辱した。国民が見守る中で裁いてくれる。","ENG":"You have insulted the motherland. You shall be judged in front of the people of this great land.","TWN":"竟敢藐視國家，你就在國民面前接受審判吧！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너희의 법에는 따를 수 없다. 역병과 결탁한 이들과는 상종하지 않는 것이 마땅할지니.","JPN":"そなたらの法には従えん。疫病と結託した者とは交わらん方がいい。","ENG":"I shall not abide by your law. The laws of those who have colluded with the plague have no power over me.","TWN":"我無法遵守你們的法律，因為我不會和勾結瘟疫的人打交道。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"같잖은 연기 집어치워라. 네가 그래 봐야 결국 알량한 힘을 믿는 카운터겠지.","JPN":"くだらない演技はやめろ。結局はつまらない力に頼るカウンターだろう。","ENG":"Enough with this ridiculous performance. I suppose you’re nothing but an overconfident Counter.","TWN":"少在那邊胡言亂語，我看你也不過就是憑藉微薄力量的制裁者。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"우리는 어떤 희생을 감수해서라도 너를 처단할 거다.","JPN":"私たちはどんな犠牲を払ってでも、お前を処断する。","ENG":"We will punish you at all costs.","TWN":"無論要犧牲多少人，我們都會處決你的！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"네 뜻이 그러하다면 그대로 행하라.","JPN":"そなたの志がそうであれば思うままにせよ。","ENG":"If that is your will, then execute it.","TWN":"有本事就試試看吧。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"허나 제 아무리 고결한 뜻인들, 무지한 자들 뒤에 숨어 외치는 한 바람처럼 가벼울 따름이로다.","JPN":"だがいくら高潔な志であろうとも、無知な者たちの背後に隠れて叫ぶ限り、風のように軽いものでしかない。","ENG":"However, no matter how noble the goal, it is meaningless coming from the ignorant, who shouts his opinion in hiding. Such will is as weak and light as a gentle breeze.","TWN":"不過就算你講得再好聽，躲在眾人背後大放厥詞的人根本不足畏懼。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"……그래. 숨어서 외치면 소용없지.","JPN":"……そうね。隠れて叫んでちゃ意味がない。","ENG":"...Agreed. There is no point in shouting while hiding.","TWN":"……沒錯，躲在後面大放厥詞是沒用的。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너는…….","JPN":"貴様は……","ENG":"You...","TWN":"你是……"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"마에스트로와 친분이 있던 여인이로군.","JPN":"マエストロと親交があった女だな。","ENG":"The woman acquainted with Maestra.","TWN":"和指揮家一起的女人。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너에게는 용무가 없다. 어찌하여 내 앞을 가로막는 것인가.","JPN":"貴様には用がない。何故我の前に立ちふさがる。","ENG":"I have no business with you. Why do you stand in my way?","TWN":"我不是來找你的，你為何要攔住我的去路？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"간단해. 레아를 괴롭혔잖아.","JPN":"簡単よ。レアをいじめたでしょう。","ENG":"It’s simple. You messed with Leah.","TWN":"答案很簡單，因為你弄傷蕾亞。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"레아도 아주머니도, 둘 다 내가 돌봐 온 인간들이야. 힘들지만 보람 있는 나날이었어.","JPN":"レアもおばさんも、両方とも私が面倒を見てきた人間たちなの。大変だったけどやりがいのある毎日だった。","ENG":"Both Leah and Madam, are humans that I look after. It’s been difficult, but very fruitful and enjoyable.","TWN":"蕾亞和伯母都是我在照顧的人類，雖然每天都很累，卻累得很值得。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};